// ═══════════════════════════════════════════════════════════════
// PROFESSIONAL QUESTION RENDERER
// Handles: normal, match, reaction, figure, assertion questions
// ═══════════════════════════════════════════════════════════════

// Parse match-the-column question
function parseMatchQuestion(qText) {
  const col2Idx = qText.search(/Column[-\s]?II\b|List[-\s]?II\b|Column[-\s]?2\b/i);
  if (col2Idx === -1) return null;
  const col1Idx = qText.search(/Column[-\s]?I\b|List[-\s]?I\b|Column[-\s]?1\b/i);
  const instruction = (col1Idx > 0 ? qText.substring(0, col1Idx) : '').trim()
    .replace(/match\s+the\s+following\s*[:.]?\s*/i,'').trim();
  const colData = qText.substring(col1Idx >= 0 ? col1Idx : 0);
  const trailingRx = /which of the following|select the correct|identify the correct|code\s*:/i;
  const trailingIdx = trailingRx.test(colData) ? colData.search(trailingRx) : colData.length;
  const trailing = trailingIdx < colData.length ? colData.substring(trailingIdx).trim() : '';
  const colSection = colData.substring(0, trailingIdx);
  const col2MatchRx = /Column[-\s]?II\b|List[-\s]?II\b|Column[-\s]?2\b/i;
  const col2MatchResult = colSection.match(col2MatchRx);
  const col2Start = col2MatchResult ? colSection.search(col2MatchRx) : -1;
  const col1Section = col2Start > 0 ? colSection.substring(0, col2Start) : '';
  const col2Section = col2Start >= 0 ? colSection.substring(col2Start + col2MatchResult[0].length) : '';
  function extractItems(text) {
    const patterns = [
      /\(([A-D])\)\s+(.+?)(?=\s*\([A-D]\)|$)/g,
      /\(([ivxIVX]{1,4})\)\s+(.+?)(?=\s*\([ivxIVX]{1,4}\)|$)/g,
      /\b([A-D])\.\s+(.+?)(?=\s+[A-D]\.|$)/g,
      /\b([P-S])\.\s+(.+?)(?=\s+[P-S]\.|$)/g,
      /\b(\d+)\.\s+(.+?)(?=\s+\d+\.|$)/g,
    ];
    for (const pat of patterns) {
      pat.lastIndex = 0;
      const found = [];
      let m;
      while ((m = pat.exec(text)) !== null) {
        found.push({ key: m[1].trim(), val: m[2].trim().replace(/\s+/g,' ') });
      }
      if (found.length >= 2) return found;
    }
    return [];
  }
  const col1Items = extractItems(col1Section || colSection);
  const col2Items = extractItems(col2Section);
  if (col1Items.length >= 2 && col2Items.length >= 2) {
    return { instruction, col1: col1Items, col2: col2Items, trailing };
  }
  return null;
}

// Render question body based on type
function QuestionBody({ q, isMobile }) {
  const type = q.type || 'normal';

  // ── TYPE BADGE ──────────────────────────────────────────────
  const TypeBadge = () => {
    const badges = {
      figure:    { bg:'#FFFBEB', border:'#FDE68A', color:'#92400E', icon:'📊', text:'Diagram-based question' },
      match:     { bg:'#F0FDF4', border:'#BBF7D0', color:'#166534', icon:'🔗', text:'Match the Column' },
      reaction:  { bg:'#EFF6FF', border:'#BFDBFE', color:'#1E40AF', icon:'⚗️', text:'Reaction Sequence' },
      assertion: { bg:'#FDF4FF', border:'#E9D5FF', color:'#6B21A8', icon:'💡', text:'Assertion & Reason' },
    };
    const b = badges[type];
    if (!b) return null;
    return (
      <div style={{
        display:'flex', alignItems:'center', gap:'8px',
        background:b.bg, border:`1px solid ${b.border}`,
        borderRadius:'8px', padding:'8px 12px', marginBottom:'14px',
        fontSize:'13px', color:b.color, fontWeight:500
      }}>
        <span>{b.icon}</span>
        <span><b>{b.text}</b></span>
      </div>
    );
  };

  // ── MATCH THE COLUMN ────────────────────────────────────────
  if (type === 'match') {
    const parsed = parseMatchQuestion(q.q);
    if (parsed) {
      return (
        <div>
          <TypeBadge />
          {parsed.instruction && (
            <p style={{ fontSize:'15px', lineHeight:'1.7', color:'#1E293B',
                        marginBottom:'16px', fontWeight:500 }}>
              {parsed.instruction}
            </p>
          )}
          {/* Two-column table */}
          <div style={{
            display:'grid',
            gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr',
            gap:'2px', border:'1.5px solid #CBD5E1',
            borderRadius:'10px', overflow:'hidden',
            marginBottom:'14px', fontSize:'14px'
          }}>
            {/* Column headers */}
            <div style={{
              background:'#1E293B', color:'#fff',
              padding:'10px 14px', fontWeight:700, fontSize:'13px',
              letterSpacing:'0.3px'
            }}>Column I</div>
            <div style={{
              background:'#1E293B', color:'#fff',
              padding:'10px 14px', fontWeight:700, fontSize:'13px',
              letterSpacing:'0.3px',
              borderLeft: isMobile ? 'none' : '1px solid #334155'
            }}>Column II</div>
            {/* Rows */}
            {parsed.col1.map((item, i) => (
              <React.Fragment key={i}>
                <div style={{
                  background: i%2===0 ? '#F8FAFC' : '#fff',
                  padding:'10px 14px', borderTop:'1px solid #E2E8F0',
                  color:'#1E293B', lineHeight:'1.6'
                }}>
                  <span style={{
                    display:'inline-flex', alignItems:'center', justifyContent:'center',
                    background:'#2563EB', color:'#fff',
                    borderRadius:'50%', width:'22px', height:'22px',
                    fontSize:'12px', fontWeight:700, marginRight:'8px',
                    flexShrink:0
                  }}>{item.key}</span>
                  {item.val}
                </div>
                <div style={{
                  background: i%2===0 ? '#F8FAFC' : '#fff',
                  padding:'10px 14px', borderTop:'1px solid #E2E8F0',
                  borderLeft: isMobile ? 'none' : '1px solid #E2E8F0',
                  color:'#1E293B', lineHeight:'1.6'
                }}>
                  {parsed.col2[i] ? (
                    <>
                      <span style={{
                        display:'inline-flex', alignItems:'center', justifyContent:'center',
                        background:'#10B981', color:'#fff',
                        borderRadius:'50%', width:'22px', height:'22px',
                        fontSize:'12px', fontWeight:700, marginRight:'8px',
                        flexShrink:0
                      }}>{parsed.col2[i].key}</span>
                      {parsed.col2[i].val}
                    </>
                  ) : '—'}
                </div>
              </React.Fragment>
            ))}
          </div>
          {parsed.trailing && (
            <p style={{ fontSize:'14px', color:'#475569',
                        lineHeight:'1.6', marginTop:'4px' }}>
              {parsed.trailing}
            </p>
          )}
        </div>
      );
    }
  }

  // ── ASSERTION & REASON ──────────────────────────────────────
  if (type === 'assertion') {
    const assertMatch = q.q.match(/Assertion\s*[\(A\):]+\s*(.+?)\s*Reason\s*[\(R\):]+\s*(.+)/is);
    if (assertMatch) {
      return (
        <div>
          <TypeBadge />
          <div style={{
            border:'1.5px solid #E9D5FF', borderRadius:'10px',
            overflow:'hidden', marginBottom:'10px', fontSize:'14px'
          }}>
            <div style={{
              background:'#6B21A8', color:'#fff',
              padding:'8px 14px', fontWeight:700, fontSize:'12px',
              letterSpacing:'0.5px', textTransform:'uppercase'
            }}>Assertion (A)</div>
            <div style={{
              background:'#FDF4FF', padding:'12px 14px',
              color:'#1E293B', lineHeight:'1.7'
            }}>{assertMatch[1].trim()}</div>
            <div style={{
              background:'#6B21A8', color:'#fff',
              padding:'8px 14px', fontWeight:700, fontSize:'12px',
              letterSpacing:'0.5px', textTransform:'uppercase',
              borderTop:'1px solid #E9D5FF'
            }}>Reason (R)</div>
            <div style={{
              background:'#fff', padding:'12px 14px',
              color:'#1E293B', lineHeight:'1.7'
            }}>{assertMatch[2].trim()}</div>
          </div>
          <p style={{
            fontSize:'13px', color:'#64748B', lineHeight:'1.6',
            background:'#F8FAFC', borderRadius:'8px', padding:'10px 12px',
            border:'1px solid #E2E8F0'
          }}>
            (A) Both A and R are true, R is the correct explanation of A<br/>
            (B) Both A and R are true, R is not the correct explanation of A<br/>
            (C) A is true but R is false<br/>
            (D) A is false but R is true
          </p>
        </div>
      );
    }
  }

  // ── FIGURE BASED ────────────────────────────────────────────
  if (type === 'figure') {
    return (
      <div>
        <TypeBadge />
        <div style={{
          background:'#FFFBEB', border:'2px dashed #FDE68A',
          borderRadius:'10px', padding:'20px',
          textAlign:'center', marginBottom:'14px', color:'#92400E'
        }}>
          <div style={{fontSize:'40px', marginBottom:'8px'}}>📊</div>
          <div style={{fontSize:'13px', fontWeight:600}}>
            Refer to figure in NCERT textbook
          </div>
          <div style={{fontSize:'12px', color:'#B45309', marginTop:'4px'}}>
            Chapter: {q.ch || 'See source material'}
          </div>
        </div>
        <p style={{
          fontSize:'15px', lineHeight:'1.8', color:'#1E293B',
          whiteSpace:'pre-wrap'
        }}>{q.q.replace(/\b(given figure|the figure|shown in figure|diagram below)\b/gi,'[figure]')}</p>
      </div>
    );
  }

  // ── REACTION SEQUENCE ────────────────────────────────────────
  if (type === 'reaction') {
    // Break at → for better display
    const parts = q.q.split(/(→|⟶)/);
    if (parts.length > 1) {
      return (
        <div>
          <TypeBadge />
          <div style={{
            background:'#EFF6FF', border:'1.5px solid #BFDBFE',
            borderRadius:'10px', padding:'16px', marginBottom:'10px',
            fontFamily:"'Courier New', Consolas, monospace",
            fontSize: isMobile ? '13px' : '14px',
            color:'#1E40AF', lineHeight:'2',
            overflowX:'auto', whiteSpace:'pre-wrap',
            wordBreak:'break-word'
          }}>
            {parts.map((part, i) =>
              (part === '→' || part === '⟶')
                ? <span key={i} style={{
                    fontSize:'18px', fontWeight:700,
                    color:'#2563EB', padding:'0 4px'
                  }}>{part}</span>
                : <span key={i}>{part}</span>
            )}
          </div>
        </div>
      );
    }
  }

  // ── NORMAL QUESTION ──────────────────────────────────────────
  // Check for inline numbered statements (I., II., III.)
  const hasStatements = /\b(I\.|II\.|III\.|IV\.|1\.|2\.|3\.|4\.)\s/.test(q.q);
  if (hasStatements) {
    const introMatch = q.q.match(/^(.+?)\s+(I\.|1\.)/s);
    const intro = introMatch ? introMatch[1].trim() : '';
    const stmtText = introMatch ? q.q.substring(intro.length).trim() : q.q;
    const stmts = stmtText.split(/(?=\b(?:I{1,3}V?|IV|[1-4])\.\s)/);

    return (
      <div>
        {intro && <p style={{
          fontSize:'15px', lineHeight:'1.8', color:'#1E293B',
          marginBottom:'12px', fontWeight:500
        }}>{intro}</p>}
        <div style={{
          border:'1.5px solid #E2E8F0', borderRadius:'10px',
          overflow:'hidden', marginBottom:'10px', fontSize:'14px'
        }}>
          {stmts.filter(s=>s.trim()).map((stmt, i) => (
            <div key={i} style={{
              display:'flex', gap:'10px',
              padding:'10px 14px', lineHeight:'1.7',
              background: i%2===0 ? '#F8FAFC' : '#fff',
              borderTop: i>0 ? '1px solid #E2E8F0' : 'none',
              color:'#1E293B'
            }}>
              <span style={{
                flexShrink:0, fontWeight:700, color:'#2563EB',
                minWidth:'24px'
              }}>{stmt.match(/^[\w.]+/)?.[0]}</span>
              <span>{stmt.replace(/^[\w.]+\s*/,'')}</span>
            </div>
          ))}
        </div>
      </div>
    );
  }

  // Plain normal question
  return (
    <p style={{
      fontSize: isMobile ? '15px' : '16px',
      lineHeight:'1.85', color:'#1E293B', margin:0,
      fontWeight:450, whiteSpace:'pre-wrap',
      letterSpacing:'0.01em', wordBreak:'break-word'
    }}>{q.q}</p>
  );
}


function shuffle(arr) { return [...arr].sort(() => Math.random() - 0.5); }
function qKey(q) { return (q?.q || '').substring(0, 60).replace(/\s+/g, '_'); }
function fmt(s) {
  const m = Math.floor(s / 60), r = s % 60;
  return `${String(m).padStart(2, "0")}:${String(r).padStart(2, "0")}`;
}

